 {"id":"bd-k5q5.6.4","title":"Troubleshooting guide for harness and policy failures","description":"Common failure signatures should map to root causes and concrete remediation steps.","design":"Create troubleshooting catalog for path normalization mismatches, UI dispatch issues, policy denials, and parity skip classes.","acceptance_criteria":"Guide shortens mean-time-to-resolution for recurrent issues. Evidence must include linked unit and end-to-end test outcomes with structured logs in the conformance artifact set. Completion must include linked unit-test evidence, end-to-end (e2e) workflow script evidence, and structured logs that support deterministic triage.","notes":"Link each signature to relevant tests and source locations.","status":"open","priority":2,"issue_type":"task","created_at":"2026-02-07T22:05:14.396364440Z","created_by":"ubuntu","updated_at":"2026-02-07T23:57:58.041656695Z","source_repo":".","compaction_level":0,"original_size":0,"labels":["docs","security","troubleshooting"],"dependencies":[{"issue_id":"bd-k5q5.6.4","depends_on_id":"bd-k5q5.1.8","type":"blocks","created_at":"2026-02-07T22:05:22.717383618Z","created_by":"ubuntu"},{"issue_id":"bd-k5q5.6.4","depends_on_id":"bd-k5q5.2.6","type":"blocks","created_at":"2026-02-07T22:05:22.875541343Z","created_by":"ubuntu"},{"issue_id":"bd-k5q5.6.4","depends_on_id":"bd-k5q5.4.6","type":"blocks","created_at":"2026-02-07T22:05:23.051885082Z","created_by":"ubuntu"},{"issue_id":"bd-k5q5.6.4","depends_on_id":"bd-k5q5.6","type":"parent-child","created_at":"2026-02-07T22:05:14.396364440Z","created_by":"ubuntu"},{"issue_id":"bd-k5q5.6.4","depends_on_id":"bd-k5q5.7.7","type":"blocks","created_at":"2026-02-07T22:55:57.958849446Z","created_by":"ubuntu"},{"issue_id":"bd-k5q5.6.4","depends_on_id":"bd-k5q5.7.9","type":"blocks","created_at":"2026-02-07T22:55:58.120752675Z","created_by":"ubuntu"}]}
 {"id":"bd-k5q5.6.5","title":"Program governance: roadmap, ownership, and maintenance cadence","description":"Long-lived quality requires clear ownership and review cadence.","design":"Define roadmap update rhythm, ownership model, exception review cadence, and success metrics reporting.","acceptance_criteria":"Program continues sustainably after initial push, with accountable owners and review checkpoints. Evidence must include linked unit and end-to-end test outcomes with structured logs in the conformance artifact set. Completion must include linked unit-test evidence, end-to-end (e2e) workflow script evidence, and structured logs that support deterministic triage.","notes":"This closes the loop from implementation to ongoing operation.","status":"open","priority":2,"issue_type":"task","created_at":"2026-02-07T22:05:14.781890868Z","created_by":"ubuntu","updated_at":"2026-02-07T23:58:04.844746264Z","source_repo":".","compaction_level":0,"original_size":0,"labels":["docs","governance","program"],"dependencies":[{"issue_id":"bd-k5q5.6.5","depends_on_id":"bd-k5q5.6","type":"parent-child","created_at":"2026-02-07T22:05:14.781890868Z","created_by":"ubuntu"},{"issue_id":"bd-k5q5.6.5","depends_on_id":"bd-k5q5.6.1","type":"blocks","created_at":"2026-02-07T22:05:23.212965931Z","created_by":"ubuntu"},{"issue_id":"bd-k5q5.6.5","depends_on_id":"bd-k5q5.6.2","type":"blocks","created_at":"2026-02-07T22:05:23.374639563Z","created_by":"ubuntu"},{"issue_id":"bd-k5q5.6.5","depends_on_id":"bd-k5q5.6.3","type":"blocks","created_at":"2026-02-07T22:05:23.532775447Z","created_by":"ubuntu"},{"issue_id":"bd-k5q5.6.5","depends_on_id":"bd-k5q5.6.4","type":"blocks","created_at":"2026-02-07T22:05:23.691116624Z","created_by":"ubuntu"},{"issue_id":"bd-k5q5.6.5","depends_on_id":"bd-k5q5.7.11","type":"blocks","created_at":"2026-02-07T22:55:58.285191376Z","created_by":"ubuntu"},{"issue_id":"bd-k5q5.6.5","depends_on_id":"bd-k5q5.7.13","type":"blocks","created_at":"2026-02-07T23:08:28.350094298Z","created_by":"ubuntu"},{"issue_id":"bd-k5q5.6.5","depends_on_id":"bd-k5q5.7.14","type":"blocks","created_at":"2026-02-07T23:58:04.844698365Z","created_by":"ubuntu"}]}
 {"id":"bd-k5q5.7","title":"Comprehensive Verification Program: unit tests, end-to-end scripts, and detailed diagnostics logging","description":"Cross-cutting verification epic to guarantee every capability in the extension platform is provably correct via layered tests and high-quality logs. This exists to prevent false confidence and to make failures quickly diagnosable by engineers and users.","design":"Create a traceability matrix first, then implement layered test suites (unit, integration, e2e, fault-injection, soak), plus logging contracts and operator-friendly tooling.","acceptance_criteria":"Every major runtime surface and workflow is covered by deterministic unit tests and end-to-end scripts with structured logs, and evidence is consumable in CI and local workflows. Completion must include linked unit-test evidence, end-to-end (e2e) workflow script evidence, and structured logs that support deterministic triage.","notes":"This epic is intentionally additive and does not remove or reduce any existing feature scope.","status":"open","priority":0,"issue_type":"epic","created_at":"2026-02-07T22:55:42.837870609Z","created_by":"ubuntu","updated_at":"2026-02-07T23:57:58.495534546Z","source_repo":".","compaction_level":0,"original_size":0,"labels":["e2e","logging","quality","tests"],"dependencies":[{"issue_id":"bd-k5q5.7","depends_on_id":"bd-k5q5","type":"parent-child","created_at":"2026-02-07T22:55:42.837870609Z","created_by":"ubuntu"}]}
-{"id":"bd-k5q5.7.1","title":"Traceability matrix linking requirements to unit tests, e2e scripts, and evidence logs","description":"Need explicit traceability from beads to test coverage so no requirement ships without proof.","design":"Build an initial traceability matrix early, then keep it continuously synchronized as tests evolve. Map each bd-k5q5 acceptance criterion to concrete unit tests, e2e scripts, and artifact paths, with machine checks for stale mappings.","acceptance_criteria":"Matrix is committed, machine-readable, initially bootstrapped, and continuously validated by CI to detect uncovered or stale requirement-to-test mappings. Completion must include linked unit-test evidence, end-to-end (e2e) workflow script evidence, and structured logs that support deterministic triage.","notes":"This remains mandatory for governance, but implementation work should proceed in parallel and feed updates back into the matrix.","status":"in_progress","priority":0,"issue_type":"task","created_at":"2026-02-07T22:55:43.270727918Z","created_by":"ubuntu","updated_at":"2026-02-07T23:57:58.717843803Z","source_repo":".","compaction_level":0,"original_size":0,"labels":["governance","tests","traceability"],"dependencies":[{"issue_id":"bd-k5q5.7.1","depends_on_id":"bd-k5q5.7","type":"parent-child","created_at":"2026-02-07T22:55:43.270727918Z","created_by":"ubuntu"}]}
+{"id":"bd-k5q5.7.1","title":"Traceability matrix linking requirements to unit tests, e2e scripts, and evidence logs","description":"Need explicit traceability from beads to test coverage so no requirement ships without proof.","design":"Build an initial traceability matrix early, then keep it continuously synchronized as tests evolve. Map each bd-k5q5 acceptance criterion to concrete unit tests, e2e scripts, and artifact paths, with machine checks for stale mappings.","acceptance_criteria":"Matrix is committed, machine-readable, initially bootstrapped, and continuously validated by CI to detect uncovered or stale requirement-to-test mappings. Completion must include linked unit-test evidence, end-to-end (e2e) workflow script evidence, and structured logs that support deterministic triage.","notes":"This remains mandatory for governance, but implementation work should proceed in parallel and feed updates back into the matrix.","status":"closed","priority":0,"issue_type":"task","created_at":"2026-02-07T22:55:43.270727918Z","created_by":"ubuntu","updated_at":"2026-02-08T00:07:25.518072038Z","closed_at":"2026-02-08T00:07:25.518041060Z","close_reason":"Completed: matrix checker + CI guard + docs linkage","source_repo":".","compaction_level":0,"original_size":0,"labels":["governance","tests","traceability"],"dependencies":[{"issue_id":"bd-k5q5.7.1","depends_on_id":"bd-k5q5.7","type":"parent-child","created_at":"2026-02-07T22:55:43.270727918Z","created_by":"ubuntu"}]}
 {"id":"bd-k5q5.7.10","title":"Soak and longevity end-to-end verification","description":"Short tests miss leaks and long-session degradation.","design":"Add long-running e2e scripts for sustained extension sessions, repeated tool calls, and profile toggling under load.","acceptance_criteria":"Soak reports include memory, timing, and error-rate trends with structured logs and pass/fail thresholds. Completion must include linked unit-test evidence, end-to-end (e2e) workflow script evidence, and structured logs that support deterministic triage.","notes":"This protects real-world reliability for heavy users.","status":"open","priority":1,"issue_type":"task","created_at":"2026-02-07T22:55:47.342307098Z","created_by":"ubuntu","updated_at":"2026-02-07T23:57:58.939951335Z","source_repo":".","compaction_level":0,"original_size":0,"labels":["e2e","reliability","soak","tests"],"dependencies":[{"issue_id":"bd-k5q5.7.10","depends_on_id":"bd-k5q5.7","type":"parent-child","created_at":"2026-02-07T22:55:47.342307098Z","created_by":"ubuntu"},{"issue_id":"bd-k5q5.7.10","depends_on_id":"bd-k5q5.7.5","type":"blocks","created_at":"2026-02-07T22:55:52.496442474Z","created_by":"ubuntu"},{"issue_id":"bd-k5q5.7.10","depends_on_id":"bd-k5q5.7.8","type":"blocks","created_at":"2026-02-07T22:55:52.946326439Z","created_by":"ubuntu"}]}
 {"id":"bd-k5q5.7.11","title":"User-focused verification reports and release-readiness summary","description":"Evidence should be understandable to users and maintainers, not just test authors.","design":"Generate concise release-readiness reports summarizing compatibility coverage, blocked operations, risk posture, known exceptions, and confidence signals.","acceptance_criteria":"Reports are generated automatically from test artifacts and directly answer whether users can safely run extensions in each profile, including real-user workflow outcomes and known-risk remediation guidance. Completion must include linked unit-test evidence, end-to-end (e2e) workflow script evidence, and structured logs that support deterministic triage.","notes":"Improves decision quality for shipping and support.","status":"open","priority":1,"issue_type":"task","created_at":"2026-02-07T22:55:47.785437087Z","created_by":"ubuntu","updated_at":"2026-02-07T23:57:59.171879388Z","source_repo":".","compaction_level":0,"original_size":0,"labels":["reporting","tests","user-experience"],"dependencies":[{"issue_id":"bd-k5q5.7.11","depends_on_id":"bd-k5q5.7","type":"parent-child","created_at":"2026-02-07T22:55:47.785437087Z","created_by":"ubuntu"},{"issue_id":"bd-k5q5.7.11","depends_on_id":"bd-k5q5.7.10","type":"blocks","created_at":"2026-02-07T22:55:55.530807170Z","created_by":"ubuntu"},{"issue_id":"bd-k5q5.7.11","depends_on_id":"bd-k5q5.7.5","type":"blocks","created_at":"2026-02-07T22:55:55.007903734Z","created_by":"ubuntu"},{"issue_id":"bd-k5q5.7.11","depends_on_id":"bd-k5q5.7.9","type":"blocks","created_at":"2026-02-07T22:55:55.271076963Z","created_by":"ubuntu"}]}
 {"id":"bd-k5q5.7.12","title":"Traceability governance gate: stale-mapping detection and enforcement","description":"Parallel test implementation can drift from requirements unless a strict governance check is enforced.","design":"Implement automated checks that fail CI when acceptance criteria lack mapped tests/e2e scripts/log artifacts or when mappings reference missing assets.","acceptance_criteria":"CI blocks merges when traceability coverage or freshness drops below defined thresholds; diagnostics point directly to missing mappings. Evidence must include linked unit and end-to-end test outcomes with structured logs in the conformance artifact set. Completion must include linked unit-test evidence, end-to-end (e2e) workflow script evidence, and structured logs that support deterministic triage.","notes":"This preserves rigor while allowing execution parallelism.","status":"open","priority":0,"issue_type":"task","created_at":"2026-02-07T23:08:22.551787790Z","created_by":"ubuntu","updated_at":"2026-02-07T23:57:59.403157182Z","source_repo":".","compaction_level":0,"original_size":0,"labels":["ci","governance","tests","traceability"],"dependencies":[{"issue_id":"bd-k5q5.7.12","depends_on_id":"bd-k5q5.7","type":"parent-child","created_at":"2026-02-07T23:08:22.551787790Z","created_by":"ubuntu"},{"issue_id":"bd-k5q5.7.12","depends_on_id":"bd-k5q5.7.1","type":"blocks","created_at":"2026-02-07T23:08:22.920068798Z","created_by":"ubuntu"},{"issue_id":"bd-k5q5.7.12","depends_on_id":"bd-k5q5.7.2","type":"blocks","created_at":"2026-02-07T23:08:23.105930775Z","created_by":"ubuntu"},{"issue_id":"bd-k5q5.7.12","depends_on_id":"bd-k5q5.7.3","type":"blocks","created_at":"2026-02-07T23:08:23.292358427Z","created_by":"ubuntu"},{"issue_id":"bd-k5q5.7.12","depends_on_id":"bd-k5q5.7.4","type":"blocks","created_at":"2026-02-07T23:08:23.485671791Z","created_by":"ubuntu"},{"issue_id":"bd-k5q5.7.12","depends_on_id":"bd-k5q5.7.7","type":"blocks","created_at":"2026-02-07T23:08:23.670667805Z","created_by":"ubuntu"}]}
